-- Canonical DDL for naap.canonical_streaming_gpu_metrics_hourly_store.
-- Source of truth: this file. The resolver and MVs write rows;
-- this declaration governs the physical schema.
-- Apply with scripts/apply-store-ddl.sh; drift is caught by
-- warehouse/tests/test_store_ddl_drift.sql.

CREATE TABLE IF NOT EXISTS naap.canonical_streaming_gpu_metrics_hourly_store (`window_start` DateTime('UTC'), `org` LowCardinality(String), `orchestrator_address` String, `pipeline_id` String, `model_id` Nullable(String), `gpu_id` Nullable(String), `region` Nullable(String), `avg_output_fps` Float64, `output_fps_sum` Float64, `p95_output_fps` Float64, `output_fps_p95_state` AggregateFunction(quantileTDigest(0.95), Float64), `fps_jitter_coefficient` Nullable(Float64), `status_samples` UInt64, `error_status_samples` UInt64, `health_signal_count` UInt64 DEFAULT 0, `health_expected_signal_count` UInt64 DEFAULT 0, `health_signal_coverage_ratio` Float64, `gpu_model_name` Nullable(String), `gpu_memory_bytes_total` Nullable(UInt64), `runner_version` Nullable(String), `cuda_version` Nullable(String), `avg_prompt_to_first_frame_ms` Nullable(Float64), `prompt_to_first_frame_sum_ms` Float64, `avg_startup_latency_ms` Nullable(Float64), `startup_latency_sum_ms` Float64, `avg_e2e_latency_ms` Nullable(Float64), `e2e_latency_sum_ms` Float64, `p95_prompt_to_first_frame_latency_ms` Nullable(Float64), `prompt_to_first_frame_p95_state` AggregateFunction(quantileTDigestIf(0.95), Float64, UInt8), `p95_startup_latency_ms` Nullable(Float64), `startup_latency_p95_state` AggregateFunction(quantileTDigestIf(0.95), Float64, UInt8), `p95_e2e_latency_ms` Nullable(Float64), `e2e_latency_p95_state` AggregateFunction(quantileTDigestIf(0.95), Float64, UInt8), `prompt_to_first_frame_sample_count` UInt64, `startup_latency_sample_count` UInt64, `e2e_latency_sample_count` UInt64, `known_sessions_count` UInt64, `startup_success_sessions` UInt64, `no_orch_sessions` UInt64 DEFAULT 0, `startup_excused_sessions` UInt64, `startup_failed_sessions` UInt64 DEFAULT 0, `startup_unexcused_sessions` UInt64, `confirmed_swapped_sessions` UInt64, `inferred_swap_sessions` UInt64, `total_swapped_sessions` UInt64, `sessions_ending_in_error` UInt64, `startup_failed_rate` Float64 DEFAULT 0, `startup_unexcused_rate` Float64, `swap_rate` Float64, `refresh_run_id` String, `artifact_checksum` String DEFAULT '', `refreshed_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = MergeTree PARTITION BY (org, toYYYYMM(window_start)) ORDER BY (org, window_start, orchestrator_address, pipeline_id, ifNull(model_id, ''), ifNull(gpu_id, ''), refreshed_at) SETTINGS index_granularity = 8192;
